export const GERADOR_CRIATIVOS_HTML: string = "<!DOCTYPE html>\n<html lang=\"pt-BR\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Gerador de Criativos — Attra Veículos</title>\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,200;0,300;0,400;0,500;0,600;0,700;0,800;0,900;1,600;1,700;1,800;1,900&family=Inter:wght@400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n  :root{\n    --bg:#101014; --panel:#1a1a20; --panel2:#22222a; --line:#2e2e38;\n    --txt:#f0f0f2; --muted:#9a9aa6; --red:#9a1c1c;\n  }\n  *{box-sizing:border-box; margin:0; padding:0;}\n  body{\n    background:var(--bg); color:var(--txt);\n    font-family:'Montserrat', -apple-system, sans-serif;\n    min-height:100vh;\n  }\n  header{\n    display:flex; align-items:center; gap:16px;\n    padding:14px 28px; border-bottom:1px solid var(--line);\n    background:var(--panel);\n  }\n  header .hdr-logo{height:32px; display:block;}\n  header small{color:var(--muted); font-weight:400; font-size:15px;}\n  .wrap{\n    display:flex; gap:28px; padding:28px; align-items:flex-start;\n    max-width:1400px; margin:0 auto; flex-wrap:wrap;\n  }\n  .form{\n    flex:1 1 480px; min-width:380px; max-width:640px;\n    display:flex; flex-direction:column; gap:18px;\n  }\n  fieldset{\n    border:1px solid var(--line); border-radius:12px;\n    background:var(--panel); padding:18px;\n  }\n  legend{\n    padding:0 8px; font-size:12px; font-weight:700; letter-spacing:2px;\n    text-transform:uppercase; color:var(--muted);\n  }\n  .row{display:flex; gap:12px;}\n  .row > *{flex:1;}\n  label{display:block; font-size:11px; font-weight:600; letter-spacing:1px;\n    text-transform:uppercase; color:var(--muted); margin:10px 0 5px;}\n  input[type=text]{\n    width:100%; background:var(--panel2); border:1px solid var(--line);\n    border-radius:8px; color:var(--txt); padding:10px 12px; font-size:14px;\n    font-family:inherit;\n  }\n  input[type=text]:focus{outline:none; border-color:var(--red);}\n  input[type=file]{\n    width:100%; font-size:12px; color:var(--muted); padding:8px 0;\n  }\n  input[type=file]::file-selector-button{\n    background:var(--panel2); border:1px solid var(--line); color:var(--txt);\n    border-radius:6px; padding:7px 12px; margin-right:10px; cursor:pointer;\n    font-family:inherit; font-size:12px; font-weight:600;\n  }\n  input[type=range]{width:100%; accent-color:var(--red);}\n  .sliders{display:grid; grid-template-columns:1fr 1fr 1fr; gap:10px; margin-top:6px;}\n  .sliders label{margin:4px 0 2px;}\n  .hint{font-size:11px; color:var(--muted); margin-top:6px; line-height:1.5;}\n  .estq-item{display:block; width:100%; text-align:left; background:var(--panel2);\n    border:1px solid var(--line); color:var(--txt); border-radius:8px;\n    padding:9px 12px; margin-top:8px; cursor:pointer; font-family:inherit; font-size:13px;}\n  .estq-item:hover{border-color:var(--red);}\n  #estoquefotos{display:flex; flex-wrap:wrap; gap:8px; margin-top:10px;}\n  .estq-thumb{width:86px; height:64px; object-fit:cover; border-radius:6px;\n    border:1px solid var(--line); cursor:pointer;}\n  .estq-thumb:hover{border-color:var(--red);}\n  .btn{\n    background:var(--red); color:#fff; border:none; border-radius:10px;\n    padding:16px 20px; font-size:15px; font-weight:700; letter-spacing:1px;\n    cursor:pointer; font-family:inherit; text-transform:uppercase;\n    transition:filter .15s;\n  }\n  .btn:hover{filter:brightness(1.12);}\n  .btn.secondary{background:var(--panel2); border:1px solid var(--line); font-weight:600; text-transform:none; letter-spacing:0;}\n  /* seletor de tipo */\n  .types{display:grid; grid-template-columns:1fr 1fr 1fr; gap:10px;}\n  .typebtn, .edtemabtn{\n    background:var(--panel2); border:2px solid var(--line); border-radius:10px;\n    color:var(--muted); padding:12px 8px; cursor:pointer; text-align:center;\n    font-family:inherit; font-size:13px; font-weight:700;\n  }\n  .typebtn small, .edtemabtn small{display:block; font-weight:400; font-size:10px; margin-top:3px;}\n  .typebtn.active, .edtemabtn.active{border-color:var(--red); color:var(--txt);}\n  .carblock{\n    border:1px solid var(--line); border-radius:10px; padding:12px; margin-top:12px;\n    background:rgba(255,255,255,.02);\n  }\n  .carblock h4{font-size:12px; color:var(--red); letter-spacing:2px; margin-bottom:4px;}\n  .preview{\n    flex:0 0 auto; position:sticky; top:28px;\n    display:flex; flex-direction:column; gap:14px; align-items:center;\n  }\n  #cv{\n    width:378px; height:672px; border-radius:14px;\n    box-shadow:0 20px 60px rgba(0,0,0,.55); background:#000;\n  }\n  .preview .size{font-size:11px; color:var(--muted); letter-spacing:1px;}\n  @media (max-width:900px){ .preview{position:static;} }\n</style>\n</head>\n<body>\n\n<header>\n  <img class=\"hdr-logo\" src=\"data:image/png;base64,\" alt=\"Attra Veículos\">\n  <div class=\"mark\"><small>Gerador de Criativos — Stories 1080×1920</small></div>\n</header>\n\n<div class=\"wrap\">\n  <!-- ================= FORM ================= -->\n  <div class=\"form\">\n\n    <fieldset>\n      <legend>Tipo de criativo</legend>\n      <div class=\"types\">\n        <button class=\"typebtn active\" data-tipo=\"classico\">1 · Clássico<small>escuro, foto grande</small></button>\n        <button class=\"typebtn\" data-tipo=\"destaque\">2 · Destaque<small>claro, ficha técnica</small></button>\n        <button class=\"typebtn\" data-tipo=\"estoque\">3 · Estoque<small>lista de até 4 carros</small></button>\n        <button class=\"typebtn\" data-tipo=\"editorial\">4 · Editorial<small>luxo, minimalista</small></button>\n      </div>\n    </fieldset>\n\n    <fieldset id=\"sec-edtema\" style=\"display:none\">\n      <legend>Fundo do Editorial</legend>\n      <div class=\"types\">\n        <button class=\"edtemabtn active\" data-edtema=\"escuro\">Escuro<small>foto funde no preto</small></button>\n        <button class=\"edtemabtn\" data-edtema=\"claro\">Claro<small>foto funde no cinza-claro</small></button>\n      </div>\n    </fieldset>\n\n    <fieldset id=\"sec-busca\">\n      <legend>Buscar do estoque (opcional)</legend>\n      <div class=\"row\">\n        <div style=\"flex:3\"><label>Veículo no estoque</label>\n          <input type=\"text\" id=\"estoquebusca\" placeholder=\"Ex.: Porsche 911, GLC 300, Purosangue...\"></div>\n        <div style=\"flex:1; display:flex; align-items:flex-end\">\n          <button class=\"btn secondary\" id=\"estoquebtn\" type=\"button\" style=\"width:100%; padding:11px 10px; font-size:12px\">BUSCAR</button></div>\n      </div>\n      <div id=\"estoqueresultados\"></div>\n      <div id=\"estoquefotos\"></div>\n      <div class=\"hint\">Selecionar um veículo preenche os campos abaixo (tudo continua editável na mão).\n        Clique numa foto para usá-la como <strong>Foto principal</strong>; com Shift, vira a <strong>Foto 2</strong>.</div>\n    </fieldset>\n\n    <fieldset id=\"sec-veiculo\">\n      <legend>Veículo</legend>\n      <div class=\"row\">\n        <div><label>Marca</label><input type=\"text\" id=\"marca\" value=\"MERCEDES-BENZ\"></div>\n        <div><label>Ano</label><input type=\"text\" id=\"ano\" value=\"2024\"></div>\n      </div>\n      <label>Modelo</label>\n      <input type=\"text\" id=\"modelo\" value=\"C-300 AMG LINE\">\n      <div class=\"row\">\n        <div><label>Preço (só números)</label><input type=\"text\" id=\"preco\" value=\"335.000\"></div>\n        <div><label>Quilometragem</label><input type=\"text\" id=\"km\" value=\"34.760\"></div>\n      </div>\n      <div id=\"kmextra-wrap\">\n        <label>Complemento da linha do KM (opcional)</label>\n        <input type=\"text\" id=\"kmextra\" placeholder=\"Ex.: VEÍCULO COLECIONÁVEL\" value=\"\">\n      </div>\n    </fieldset>\n\n    <fieldset id=\"sec-destaques\">\n      <legend>Destaques (até 3, uma linha cada)</legend>\n      <input type=\"text\" id=\"b1\" value=\"Cor Cinza Selenita Magno\" style=\"margin-top:8px\">\n      <input type=\"text\" id=\"b2\" value=\"Motor 2.0 turbo gasolina 285 cv / 61,2 kgfm\" style=\"margin-top:8px\">\n      <input type=\"text\" id=\"b3\" value=\"Pacote AMG Line\" style=\"margin-top:8px\">\n      <div class=\"hint\">Deixe em branco para omitir. Cada destaque ocupa UMA linha —\n        a fonte encolhe até caber e, se ainda passar, corta com \"…\". Seja direto.</div>\n    </fieldset>\n\n    <fieldset id=\"sec-specs\" style=\"display:none\">\n      <legend>Diferenciais do carro</legend>\n      <label>Separe por vírgula (viram pílulas vermelhas)</label>\n      <input type=\"text\" id=\"selo\" placeholder=\"Ex.: 7 LUGARES, BLINDADO, ZERO KM, FULL PPF\" value=\"BLINDADO\">\n      <div class=\"hint\">Até 4 diferenciais. O tamanho das pílulas se ajusta sozinho para caber na largura.</div>\n    </fieldset>\n\n    <fieldset id=\"sec-fotos\">\n      <legend>Fotos</legend>\n      <label id=\"foto1-label\">Foto principal (frente / 3-4)</label>\n      <input type=\"file\" id=\"foto1\" accept=\"image/*\">\n      <div class=\"sliders\">\n        <div><label>Zoom</label><input type=\"range\" id=\"f1zoom\" min=\"55\" max=\"250\" value=\"100\"></div>\n        <div><label>Posição ↔</label><input type=\"range\" id=\"f1x\" min=\"0\" max=\"100\" value=\"50\"></div>\n        <div><label>Posição ↕</label><input type=\"range\" id=\"f1y\" min=\"0\" max=\"100\" value=\"50\"></div>\n      </div>\n      <div class=\"hint\" id=\"foto1-hint\">A foto entra inteira — não precisa recortar o fundo. No Clássico, fotos horizontais são enquadradas automaticamente com o carro abaixo do título.</div>\n      <label id=\"foto2-label\" style=\"margin-top:16px\">Foto secundária (traseira / lateral — rodapé)</label>\n      <input type=\"file\" id=\"foto2\" accept=\"image/*\">\n      <div class=\"sliders\">\n        <div><label>Zoom</label><input type=\"range\" id=\"f2zoom\" min=\"55\" max=\"250\" value=\"100\"></div>\n        <div><label>Posição ↔</label><input type=\"range\" id=\"f2x\" min=\"0\" max=\"100\" value=\"50\"></div>\n        <div><label>Posição ↕</label><input type=\"range\" id=\"f2y\" min=\"0\" max=\"100\" value=\"50\"></div>\n      </div>\n      <div id=\"corte-wrap\">\n        <label style=\"margin-top:12px\">Altura do corte transversal (Clássico)</label>\n        <input type=\"range\" id=\"corte\" min=\"-160\" max=\"200\" value=\"0\">\n        <div class=\"hint\">Arraste pra direita em carros ALTOS (mais área de foto);\n          pra esquerda em carros baixos (mais espaço pros destaques).</div>\n      </div>\n      <div id=\"fotos-extra\" style=\"display:none\">\n        <label style=\"margin-top:16px\">Foto de baixo 2 (opcional)</label>\n        <input type=\"file\" id=\"foto3\" accept=\"image/*\">\n        <label style=\"margin-top:12px\">Foto de baixo 3 (opcional)</label>\n        <input type=\"file\" id=\"foto4\" accept=\"image/*\">\n        <div class=\"hint\">Com 1 foto o rodapé fica inteiro; com 3, vira uma tríade lado a lado — o layout se ajusta sozinho.</div>\n      </div>\n    </fieldset>\n\n    <fieldset id=\"sec-estoque\" style=\"display:none\">\n      <legend>Lista de carros (até 4)</legend>\n      <div class=\"row\">\n        <div><label>Título — linha 1</label><input type=\"text\" id=\"et1\" value=\"NOVIDADES\"></div>\n        <div><label>Título — linha 2 (vermelho)</label><input type=\"text\" id=\"et2\" value=\"EM ESTOQUE!\"></div>\n      </div>\n      <div id=\"estoqueCars\"></div>\n      <div class=\"hint\">Carros sem nome e sem foto são omitidos; o espaçamento se ajusta sozinho. As fotos entram inteiras nos cards — sem recorte de fundo.</div>\n    </fieldset>\n\n    <fieldset>\n      <legend>Logo (opcional)</legend>\n      <input type=\"file\" id=\"logofile\" accept=\"image/png\">\n      <div class=\"hint\">As logos oficiais da Attra (branca e preta, do site) já vêm embutidas e são usadas conforme o fundo de cada formato. Envie um PNG transparente aqui apenas se quiser substituir a do formato Clássico.</div>\n      <button class=\"btn secondary\" id=\"clearlogo\" style=\"margin-top:10px; padding:9px 14px; font-size:12px;\">Voltar ao logo padrão</button>\n    </fieldset>\n\n    <button class=\"btn\" id=\"download\">⬇ Baixar PNG (1080 × 1920)</button>\n  </div>\n\n  <!-- ================= PREVIEW ================= -->\n  <div class=\"preview\">\n    <canvas id=\"cv\" width=\"1080\" height=\"1920\"></canvas>\n    <div class=\"size\">PRÉVIA EM TEMPO REAL — EXPORTA EM 1080 × 1920 PX</div>\n  </div>\n</div>\n\n<script>\n'use strict';\nconst cv  = document.getElementById('cv');\nconst ctx = cv.getContext('2d');\nconst W = 1080, H = 1920;\nconst RED = '#9a1c1c';   // vermelho oficial Attra — R154 G28 B28\n\nconst state = {\n  tipo: 'classico',\n  foto1: null, foto2: null, foto3: null, foto4: null, logo: null,\n  f1: {zoom:1, x:.5, y:.5},\n  f2: {zoom:1, x:.5, y:.5},\n  estFotos: [null, null, null, null],\n  edTema: 'escuro',\n};\n\n/* ---------- logos oficiais embutidas ---------- */\nconst officialLogo = new Image();                 // branca (fundos escuros)\nofficialLogo.onload = () => render();\nofficialLogo.src = document.querySelector('.hdr-logo').src;\n\nlet blackLogo = null;                             // preta (fundos claros), branco→transparente\nconst blackLogoImg = new Image();\nblackLogoImg.onload = () => {\n  const c = document.createElement('canvas');\n  c.width = blackLogoImg.width; c.height = blackLogoImg.height;\n  const x = c.getContext('2d');\n  x.drawImage(blackLogoImg, 0, 0);\n  const d = x.getImageData(0, 0, c.width, c.height);\n  for(let i = 0; i < d.data.length; i += 4){\n    const r = d.data[i], g = d.data[i+1], b = d.data[i+2];\n    if((r+g+b)/3 > 232 && Math.abs(r-g) < 20 && Math.abs(g-b) < 20) d.data[i+3] = 0;\n  }\n  x.putImageData(d, 0, 0);\n  blackLogo = c;\n  render();\n};\nblackLogoImg.src = 'data:image/jpeg;base64,';\n\n// fachada da loja (fundo do topo do formato Clássico — o letreiro é o logo)\nconst facadeImg = new Image();\nfacadeImg.onload = () => render();\nfacadeImg.src = 'data:image/jpeg;base64,';\n\n/* ---------- helpers ---------- */\nconst $ = id => document.getElementById(id);\nconst val = id => $(id).value.trim();\n\nfunction spacedText(text, cx, y, font, spacing, color){\n  ctx.font = font; ctx.fillStyle = color; ctx.textBaseline = 'alphabetic';\n  const chars = [...text];\n  let total = 0;\n  for(const ch of chars) total += ctx.measureText(ch).width + spacing;\n  total -= spacing;\n  let x = cx - total/2;\n  for(const ch of chars){\n    ctx.fillText(ch, x, y);\n    x += ctx.measureText(ch).width + spacing;\n  }\n  return total;\n}\nfunction spacedWidth(text, font, spacing){\n  ctx.font = font;\n  const chars = [...text];\n  let total = 0;\n  for(const ch of chars) total += ctx.measureText(ch).width + spacing;\n  return total - spacing;\n}\nfunction wrapLines(text, font, maxW){\n  ctx.font = font;\n  const words = text.split(/\\s+/), lines = [];\n  let cur = '';\n  for(const w of words){\n    const t = cur ? cur + ' ' + w : w;\n    if(ctx.measureText(t).width > maxW && cur){ lines.push(cur); cur = w; }\n    else cur = t;\n  }\n  if(cur) lines.push(cur);\n  return lines;\n}\nfunction rr(x, y, w, h, r){\n  ctx.beginPath();\n  ctx.moveTo(x+r, y);\n  ctx.arcTo(x+w, y,   x+w, y+h, r);\n  ctx.arcTo(x+w, y+h, x,   y+h, r);\n  ctx.arcTo(x,   y+h, x,   y,   r);\n  ctx.arcTo(x,   y,   x+w, y,   r);\n  ctx.closePath();\n}\nfunction drawPhoto(img, rx, ry, rw, rh, opt, mode){\n  opt = opt || {zoom:1, x:.5, y:.5};\n  ctx.save();\n  ctx.beginPath(); ctx.rect(rx, ry, rw, rh); ctx.clip();\n  // 'fit' = aspect fit (a foto inteira aparece, sem cortar o carro)\n  const base = mode === 'fit'\n    ? Math.min(rw/img.width, rh/img.height)\n    : Math.max(rw/img.width, rh/img.height);\n  const scale = base * opt.zoom;\n  const dw = img.width*scale, dh = img.height*scale;\n  const rangeX = Math.max(dw - rw, rw*.6);\n  const rangeY = Math.max(dh - rh, rh*.6);\n  const dx = rx + (rw-dw)/2 - (opt.x-.5)*rangeX;\n  const dy = ry + (rh-dh)/2 - (opt.y-.5)*rangeY;\n  if(dw < rw-1 || dh < rh-1){\n    if(mode === 'dark'){\n      // preenchimento escuro sólido (em vez de blur)\n      const gd = ctx.createLinearGradient(0, ry, 0, ry+rh);\n      gd.addColorStop(0, '#0a0a0c'); gd.addColorStop(1, '#1e1e22');\n      ctx.fillStyle = gd; ctx.fillRect(rx, ry, rw, rh);\n    } else {\n      const bs = base * 1.2;\n      ctx.filter = 'blur(45px)';\n      ctx.drawImage(img, rx+(rw-img.width*bs)/2, ry+(rh-img.height*bs)/2, img.width*bs, img.height*bs);\n      ctx.filter = 'none';\n      ctx.fillStyle = 'rgba(0,0,0,.38)';\n      ctx.fillRect(rx, ry, rw, rh);\n    }\n  }\n  ctx.drawImage(img, dx, dy, dw, dh);\n  if(mode === 'dark' && dy > ry + 2){\n    // funde o preenchimento escuro com o topo da foto (sem emenda visível)\n    const gb = ctx.createLinearGradient(0, dy - 2, 0, dy + 170);\n    gb.addColorStop(0, 'rgba(10,10,12,1)');\n    gb.addColorStop(1, 'rgba(10,10,12,0)');\n    ctx.fillStyle = gb;\n    ctx.fillRect(rx, Math.max(ry, dy - 2), rw, 172);\n  }\n  ctx.restore();\n}\nfunction autoFrameFoto1(img){\n  const rw = 1080, rh = 1000;\n  const base = Math.max(rw/img.width, rh/img.height);\n  if(state.tipo !== 'classico' || img.width/img.height <= rw/rh + .05){\n    state.f1 = {zoom:1, x:.5, y:.5};\n  } else {\n    // largura inteira: sem sobras nas laterais (sem blur lateral)\n    const zoom = Math.max(.55, Math.min((rw/img.width)/base, 1));\n    const dh = img.height * base * zoom;\n    const rangeY = Math.max(dh - rh, rh*.6);\n    const y = .5 - (rh - dh)/(2*rangeY);\n    state.f1 = {zoom, x:.5, y:Math.max(0, Math.min(1, y))};\n  }\n  $('f1zoom').value = state.f1.zoom*100;\n  $('f1x').value = state.f1.x*100;\n  $('f1y').value = state.f1.y*100;\n}\nfunction drawDefaultLogo(cx, cy, size){       // vetor reserva (se a imagem falhar)\n  const s = size/1000;\n  ctx.save();\n  ctx.translate(cx - 500*s, cy - 475*s);\n  ctx.scale(s, s);\n  ctx.fillStyle = '#ffffff';\n  ctx.beginPath();\n  ctx.moveTo(478,10); ctx.lineTo(568,10); ctx.lineTo(818,542); ctx.lineTo(668,542);\n  ctx.lineTo(524,180); ctx.lineTo(308,672); ctx.lineTo(206,631);\n  ctx.closePath(); ctx.fill();\n  ctx.beginPath();\n  ctx.moveTo(188,671); ctx.lineTo(290,713); ctx.lineTo(191,940); ctx.lineTo(71,940);\n  ctx.closePath(); ctx.fill();\n  ctx.fillStyle = RED;\n  ctx.beginPath();\n  ctx.moveTo(0,570); ctx.lineTo(820,570); ctx.lineTo(912,938);\n  ctx.closePath(); ctx.fill();\n  ctx.restore();\n}\nfunction placeholder(rx, ry, rw, rh, label, dark){\n  const g = ctx.createLinearGradient(rx, ry, rx, ry+rh);\n  if(dark === false){ g.addColorStop(0,'#d4d4d8'); g.addColorStop(1,'#bfbfc4'); }\n  else { g.addColorStop(0,'#15181c'); g.addColorStop(1,'#2a2f36'); }\n  ctx.fillStyle = g; ctx.fillRect(rx, ry, rw, rh);\n  ctx.fillStyle = dark === false ? 'rgba(0,0,0,.35)' : 'rgba(255,255,255,.25)';\n  ctx.font = '600 ' + Math.min(30, rh/5) + 'px Montserrat, sans-serif';\n  ctx.textAlign = 'center';\n  ctx.fillText(label, rx + rw/2, ry + rh*(rh > 500 ? .72 : .53));\n  ctx.textAlign = 'left';\n}\n// desenha a foto com bordas suaves (topo e laterais se fundem com o fundo)\nfunction drawPhotoFeather(img, rx, ry, rw, rh, opt){\n  opt = opt || {zoom:1, x:.5, y:.5};\n  const base  = Math.max(rw/img.width, rh/img.height);\n  const scale = base * opt.zoom;\n  const dw = img.width*scale, dh = img.height*scale;\n  const rangeX = Math.max(dw - rw, rw*.6);\n  const rangeY = Math.max(dh - rh, rh*.6);\n  const dx = rx + (rw-dw)/2 - (opt.x-.5)*rangeX;\n  const dy = ry + (rh-dh)/2 - (opt.y-.5)*rangeY;\n  const oc = document.createElement('canvas');\n  oc.width = Math.ceil(dw); oc.height = Math.ceil(dh);\n  const o = oc.getContext('2d');\n  o.drawImage(img, 0, 0, dw, dh);\n  o.globalCompositeOperation = 'destination-out';\n  let g;\n  if(dy > ry + 2){                    // borda superior esfumada\n    g = o.createLinearGradient(0, 0, 0, 180);\n    g.addColorStop(0, 'rgba(0,0,0,1)'); g.addColorStop(1, 'rgba(0,0,0,0)');\n    o.fillStyle = g; o.fillRect(0, 0, oc.width, 180);\n  }\n  if(dw < rw - 4){                    // bordas laterais esfumadas\n    g = o.createLinearGradient(0, 0, 110, 0);\n    g.addColorStop(0, 'rgba(0,0,0,1)'); g.addColorStop(1, 'rgba(0,0,0,0)');\n    o.fillStyle = g; o.fillRect(0, 0, 110, oc.height);\n    g = o.createLinearGradient(oc.width, 0, oc.width - 110, 0);\n    g.addColorStop(0, 'rgba(0,0,0,1)'); g.addColorStop(1, 'rgba(0,0,0,0)');\n    o.fillStyle = g; o.fillRect(oc.width - 110, 0, 110, oc.height);\n  }\n  ctx.save();\n  ctx.beginPath(); ctx.rect(rx, ry, rw, rh); ctx.clip();\n  ctx.drawImage(oc, dx, dy);\n  ctx.restore();\n  return dy;\n}\nfunction drawLogoWhite(cx, cy, maxW){\n  if(state.logo){\n    const lw = state.logo.width/state.logo.height > 2 ? maxW : maxW*.45;\n    const lh = state.logo.height/state.logo.width * lw;\n    ctx.drawImage(state.logo, cx - lw/2, cy - lh/2, lw, lh);\n  } else if(officialLogo.complete && officialLogo.naturalWidth){\n    const lh = officialLogo.height/officialLogo.width * maxW;\n    ctx.drawImage(officialLogo, cx - maxW/2, cy - lh/2, maxW, lh);\n  } else drawDefaultLogo(cx, cy, 148);\n}\nfunction drawLogoBlack(cx, cy, maxW){\n  if(blackLogo){\n    const lh = blackLogo.height/blackLogo.width * maxW;\n    ctx.drawImage(blackLogo, cx - maxW/2, cy - lh/2, maxW, lh);\n  }\n}\n\n/* ================================================================\n   TIPO 1 — CLÁSSICO (escuro, foto grande)\n================================================================ */\nfunction renderClassico(){\n  const PHOTO1_H = 1000;\n\n  // fachada da loja como fundo do topo — o letreiro ATTRA é o logo\n  ctx.save();\n  ctx.beginPath(); ctx.rect(0, 0, W, PHOTO1_H); ctx.clip();\n  if(facadeImg.complete && facadeImg.naturalWidth){\n    // -60px esconde o toldo e deixa o letreiro mais compacto no topo\n    // (limite prático: o letreiro começa ~70px do topo da foto)\n    ctx.drawImage(facadeImg, 0, -60, W, facadeImg.height * (W/facadeImg.width));\n  } else {\n    ctx.fillStyle = '#101013'; ctx.fillRect(0, 0, W, PHOTO1_H);\n  }\n  // (piso da fachada tratado direto na imagem editada — sem overlay)\n  ctx.restore();\n\n  // foto do carro com bordas esfumadas, fundida na fachada\n  let topGap = PHOTO1_H;\n  if(state.foto1){\n    topGap = Math.max(0, drawPhotoFeather(state.foto1, 0, 0, W, PHOTO1_H, state.f1));\n  } else {\n    ctx.fillStyle = 'rgba(255,255,255,.45)';\n    ctx.font = '600 26px Montserrat, sans-serif';\n    ctx.textAlign = 'center';\n    ctx.fillText('ENVIE A FOTO PRINCIPAL DO VEÍCULO', W/2, 750);\n    ctx.textAlign = 'left';\n  }\n\n  // gradiente p/ legibilidade do título\n  let g;\n  if(topGap < 150){\n    // foto cobre o letreiro (ex.: foto vertical ou zoom alto) — comportamento antigo\n    g = ctx.createLinearGradient(0, 0, 0, 760);\n    g.addColorStop(0, 'rgba(0,0,0,.62)');\n    g.addColorStop(.55, 'rgba(0,0,0,.28)');\n    g.addColorStop(1, 'rgba(0,0,0,0)');\n    ctx.fillStyle = g; ctx.fillRect(0, 0, W, 760);\n  } else {\n    // preserva o brilho do letreiro; escurece só a área do título\n    g = ctx.createLinearGradient(0, 170, 0, 780);\n    g.addColorStop(0, 'rgba(0,0,0,0)');\n    g.addColorStop(.22, 'rgba(0,0,0,.60)');\n    g.addColorStop(.48, 'rgba(0,0,0,.48)');\n    g.addColorStop(.75, 'rgba(0,0,0,.22)');\n    g.addColorStop(1, 'rgba(0,0,0,0)');\n    ctx.fillStyle = g; ctx.fillRect(0, 170, W, 610);\n  }\n\n  g = ctx.createLinearGradient(0, PHOTO1_H-60, 0, PHOTO1_H);\n  g.addColorStop(0, 'rgba(219,219,221,0)');\n  g.addColorStop(1, 'rgba(219,219,221,1)');\n  ctx.fillStyle = g; ctx.fillRect(0, PHOTO1_H-60, W, 60);\n\n  // logo desenhado só quando a foto cobre o letreiro da fachada\n  if(topGap < 150) drawLogoWhite(W/2, 168, 340);\n\n  const marca  = val('marca').toUpperCase();\n  const modelo = val('modelo').toUpperCase();\n  const ano    = val('ano');\n\n  // sombra suave para o título não se perder no fundo da fachada/foto\n  ctx.save();\n  ctx.shadowColor = 'rgba(0,0,0,.85)';\n  ctx.shadowBlur = 30;\n  ctx.shadowOffsetY = 3;\n\n  if(marca) spacedText(marca, W/2, 316, '600 30px Montserrat, sans-serif', 11, '#ffffff');\n\n  let msize = 96, mspace = 30;\n  while(msize > 40 && spacedWidth(modelo, `200 ${msize}px Montserrat, sans-serif`, mspace) > 980){\n    msize -= 3; mspace = Math.max(10, mspace - 1);\n  }\n  if(modelo) spacedText(modelo, W/2, 400, `200 ${msize}px Montserrat, sans-serif`, mspace, '#ffffff');\n\n  if(ano){\n    const yy = 458;\n    const tw = spacedText(ano, W/2, yy, '300 34px Montserrat, sans-serif', 15, '#ffffff');\n    ctx.strokeStyle = 'rgba(255,255,255,.9)'; ctx.lineWidth = 2;\n    ctx.beginPath();\n    ctx.moveTo(W/2 - tw/2 - 225, yy - 11); ctx.lineTo(W/2 - tw/2 - 40, yy - 11);\n    ctx.moveTo(W/2 + tw/2 + 40,  yy - 11); ctx.lineTo(W/2 + tw/2 + 225, yy - 11);\n    ctx.stroke();\n  }\n\n  ctx.restore(); // fim da sombra do título\n\n  // corte transversal ajustável: slider positivo sobe a diagonal (carros\n  // altos ganham foto); negativo desce (carros baixos ganham texto)\n  const corte = parseInt($('corte').value, 10) || 0;\n  const DIAG_L = 1440 - corte, DIAG_R = 1400 - corte;\n  g = ctx.createLinearGradient(0, PHOTO1_H, 0, DIAG_L);\n  g.addColorStop(0, '#dbdbdd'); g.addColorStop(1, '#c9c9cc');\n  ctx.fillStyle = g;\n  ctx.beginPath();\n  ctx.moveTo(0, PHOTO1_H); ctx.lineTo(W, PHOTO1_H);\n  ctx.lineTo(W, DIAG_R); ctx.lineTo(0, DIAG_L);\n  ctx.closePath(); ctx.fill();\n\n  ctx.save();\n  ctx.beginPath();\n  ctx.moveTo(0, PHOTO1_H); ctx.lineTo(W, PHOTO1_H);\n  ctx.lineTo(W, DIAG_R); ctx.lineTo(0, DIAG_L);\n  ctx.closePath(); ctx.clip();\n  ctx.fillStyle = 'rgba(255,255,255,.09)';\n  ctx.beginPath();\n  ctx.moveTo(620, PHOTO1_H); ctx.lineTo(1080, PHOTO1_H);\n  ctx.lineTo(1080, 1400); ctx.lineTo(880, 1640);\n  ctx.closePath(); ctx.fill();\n  ctx.restore();\n\n  const preco = val('preco').replace(/^R\\$\\s*/i, '');\n  if(preco) spacedText('R$ ' + preco, W/2, 1062, '300 48px Montserrat, sans-serif', 10, '#5a5a5f');\n\n  const kmParts = [];\n  if(val('km')) kmParts.push(val('km') + ' KM');\n  if(val('kmextra')) kmParts.push(val('kmextra').toUpperCase());\n  if(kmParts.length)\n    spacedText(kmParts.join('  |  '), W/2, 1118, '500 24px Montserrat, sans-serif', 5, '#6f6f74');\n\n  // Máximo 3 destaques, UMA linha cada: a fonte encolhe até caber (mín. 25px)\n  // e em último caso o texto é cortado com \"…\" — nunca quebra de linha.\n  const bullets = ['b1','b2','b3'].map(val).filter(Boolean);\n  const textX = 208, maxW = 800, lineH = 44;\n  const areaTop = 1188, areaBot = Math.min(DIAG_L, DIAG_R) - 26;\n  const items = bullets.map(b => {\n    let size = 34;\n    ctx.font = `700 ${size}px Montserrat, sans-serif`;\n    while(size > 25 && ctx.measureText(b).width > maxW){\n      size -= 1;\n      ctx.font = `700 ${size}px Montserrat, sans-serif`;\n    }\n    let text = b;\n    while(text.length > 4 && ctx.measureText(text + '…').width > maxW)\n      text = text.slice(0, -1).trimEnd();\n    if(text !== b) text += '…';\n    return { text, size };\n  });\n  let gap = 30;\n  if(items.length > 1)\n    gap = Math.max(20, Math.min(48, (areaBot - areaTop - items.length*lineH) / (items.length - 1)));\n  const totalH = items.length*lineH + gap*Math.max(0, items.length-1);\n  let by = areaTop + Math.max(0, (areaBot - areaTop - totalH)/2) + 30;\n\n  for(const it of items){\n    const iy = by - 11;\n    ctx.strokeStyle = '#1c1c1e'; ctx.lineWidth = 3.5;\n    ctx.beginPath(); ctx.arc(158, iy, 16, 0, Math.PI*2); ctx.stroke();\n    ctx.fillStyle = '#1c1c1e';\n    ctx.beginPath(); ctx.arc(158, iy, 7.5, 0, Math.PI*2); ctx.fill();\n    ctx.font = `700 ${it.size}px Montserrat, sans-serif`; ctx.fillStyle = '#161618';\n    ctx.fillText(it.text, textX, by);\n    by += lineH + gap;\n  }\n\n  ctx.save();\n  ctx.beginPath();\n  ctx.moveTo(0, DIAG_L); ctx.lineTo(W, DIAG_R);\n  ctx.lineTo(W, H); ctx.lineTo(0, H);\n  ctx.closePath(); ctx.clip();\n  if(state.foto2){\n    // A faixa é sempre preenchida por inteiro (sem sobras, sem blur).\n    // Foto mais alta que a faixa: âncora automática na BASE da foto —\n    // as rodas nunca cortam; sai céu/fundo por cima. Se o usuário mexer\n    // no slider de posição da Foto 2, o valor dele prevalece.\n    const bw = W, bh = H - DIAG_R + 20;\n    const cover = Math.max(bw/state.foto2.width, bh/state.foto2.height);\n    const dh = state.foto2.height * cover * (state.f2.zoom || 1);\n    let opt = state.f2;\n    if(dh > bh * 1.15 && state.f2.y === .5){\n      const rangeY = Math.max(dh - bh, bh*.6);\n      opt = {...state.f2, y: .5 + (dh - bh) / (2 * rangeY)};\n    }\n    drawPhoto(state.foto2, 0, DIAG_R - 20, bw, bh, opt);\n  }\n  else placeholder(0, DIAG_R, W, H - DIAG_R, 'FOTO TRASEIRA / LATERAL');\n  ctx.restore();\n\n  ctx.save();\n  ctx.beginPath();\n  ctx.moveTo(0, DIAG_L); ctx.lineTo(W, DIAG_R);\n  ctx.lineTo(W, DIAG_R + 90); ctx.lineTo(0, DIAG_L + 90);\n  ctx.closePath(); ctx.clip();\n  g = ctx.createLinearGradient(0, DIAG_R, 0, DIAG_R + 80);\n  g.addColorStop(0, 'rgba(0,0,0,.30)'); g.addColorStop(1, 'rgba(0,0,0,0)');\n  ctx.fillStyle = g;\n  ctx.fillRect(0, DIAG_R - 20, W, 130);\n  ctx.restore();\n}\n\n/* ================================================================\n   TIPO 2 — DESTAQUE (claro, ficha técnica, foto em card)\n================================================================ */\nfunction renderDestaque(){\n  // fundo claro\n  let g = ctx.createLinearGradient(0, 0, 0, H);\n  g.addColorStop(0, '#ffffff'); g.addColorStop(1, '#ededf0');\n  ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);\n\n  // logo preta no topo + filete vermelho\n  drawLogoBlack(W/2, 130, 330);\n  ctx.fillStyle = RED; ctx.fillRect(0, 232, W, 4);\n\n  const marca  = val('marca').toUpperCase();\n  const modelo = val('modelo').toUpperCase();\n\n  if(marca){\n    const tw = spacedText(marca, W/2, 322, 'italic 600 34px Montserrat, sans-serif', 8, '#1b1b1e');\n    ctx.strokeStyle = '#1b1b1e'; ctx.lineWidth = 2;\n    ctx.beginPath();\n    ctx.moveTo(W/2 - tw/2 - 140, 310); ctx.lineTo(W/2 - tw/2 - 30, 310);\n    ctx.moveTo(W/2 + tw/2 + 30, 310);  ctx.lineTo(W/2 + tw/2 + 140, 310);\n    ctx.stroke();\n  }\n\n  let msize = 76;\n  while(msize > 36 && spacedWidth(modelo, `800 ${msize}px Montserrat, sans-serif`, 6) > 940) msize -= 3;\n  if(modelo) spacedText(modelo, W/2, 424, `800 ${msize}px Montserrat, sans-serif`, 6, '#111114');\n\n  const anokm = [val('ano'), val('km') ? val('km') + ' KM' : ''].filter(Boolean).join('  ·  ');\n  if(anokm) spacedText(anokm, W/2, 482, 'italic 500 32px Montserrat, sans-serif', 4, '#55555a');\n\n  // preço sóbrio (texto simples, sem pílula)\n  const preco = val('preco').replace(/^R\\$\\s*/i, '');\n  if(preco) spacedText('R$ ' + preco, W/2, 556, '700 48px Montserrat, sans-serif', 3, '#1b1b1e');\n\n  // pílulas com os diferenciais do carro (o verdadeiro destaque)\n  const chips = val('selo').split(',').map(s => s.trim().toUpperCase()).filter(Boolean).slice(0, 4);\n  if(chips.length){\n    const font = s => `italic 700 ${s}px Montserrat, sans-serif`;\n    let fsize = 27;\n    const totalW = s => {\n      ctx.font = font(s);\n      return chips.reduce((a, c) => a + ctx.measureText(c).width + 60, 0) + (chips.length-1)*16;\n    };\n    while(fsize > 17 && totalW(fsize) > 950) fsize -= 1;\n    ctx.font = font(fsize);\n    const widths = chips.map(c => ctx.measureText(c).width + 60);\n    const total = widths.reduce((a, b) => a + b, 0) + (chips.length-1)*16;\n    let x = W/2 - total/2;\n    const ph = Math.round(fsize*2.15), py = 604;\n    chips.forEach((c, i) => {\n      ctx.fillStyle = RED;\n      rr(x, py, widths[i], ph, ph/2); ctx.fill();\n      ctx.fillStyle = '#ffffff';\n      ctx.font = font(fsize);\n      ctx.textAlign = 'center';\n      ctx.fillText(c, x + widths[i]/2, py + ph/2 + fsize*.36);\n      ctx.textAlign = 'left';\n      x += widths[i] + 16;\n    });\n  }\n\n  // card da foto principal (foto inteira, sem recorte de fundo)\n  const cx0 = 90, cy0 = 706, cw = 900, ch = 636;\n  ctx.save();\n  ctx.shadowColor = 'rgba(0,0,0,.20)'; ctx.shadowBlur = 32; ctx.shadowOffsetY = 12;\n  ctx.fillStyle = '#fff';\n  rr(cx0, cy0, cw, ch, 26); ctx.fill();\n  ctx.restore();\n  ctx.save();\n  rr(cx0, cy0, cw, ch, 26); ctx.clip();\n  if(state.foto1) drawPhoto(state.foto1, cx0, cy0, cw, ch, state.f1);\n  else placeholder(cx0, cy0, cw, ch, 'FOTO DO VEÍCULO', false);\n  ctx.restore();\n\n  // rodapé com 1 a 3 fotos (o layout se ajusta sozinho)\n  const bots = [state.foto2, state.foto3, state.foto4].filter(Boolean);\n  const py0 = 1412, phh = H - py0;\n  ctx.fillStyle = RED; ctx.fillRect(0, py0 - 5, W, 5);\n  if(!bots.length){\n    placeholder(0, py0, W, phh, 'FOTOS DE BAIXO (1 OU 3)', false);\n  } else if(bots.length === 1){\n    drawPhoto(bots[0], 0, py0, W, phh, state.f2);\n  } else {\n    const gap = 6, colW = (W - gap*(bots.length - 1)) / bots.length;\n    bots.forEach((img, i) => {\n      drawPhoto(img, Math.round(i*(colW+gap)), py0, Math.round(colW), phh,\n                i === 0 ? state.f2 : undefined);\n    });\n  }\n}\n\n/* ================================================================\n   TIPO 3 — ESTOQUE (lista de até 4 carros)\n================================================================ */\nfunction renderEstoque(){\n  // fundo\n  let g = ctx.createLinearGradient(0, 0, 0, H);\n  g.addColorStop(0, '#efefef'); g.addColorStop(1, '#dfdfe2');\n  ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);\n\n  // linhas retas diagonais, ancoradas na geometria do logo\n  // (mesma inclinação da faixa vermelha do \"A\": ~0.4)\n  const m = 0.4;\n  const diag = (c, color, wdt, x0, x1) => {\n    ctx.strokeStyle = color; ctx.lineWidth = wdt; ctx.lineCap = 'butt';\n    ctx.beginPath();\n    ctx.moveTo(x0, m*x0 + c); ctx.lineTo(x1, m*x1 + c);\n    ctx.stroke();\n  };\n  // canto superior direito\n  diag(-330, RED, 18, 700, 1120);\n  diag(-376, '#2a2a2f', 13, 800, 1120);\n  diag(-422, '#b9b9be', 9, 900, 1120);\n  // canto inferior esquerdo (eco discreto)\n  diag(1806, RED, 18, -40, 320);\n  diag(1852, '#2a2a2f', 13, -40, 220);\n  diag(1898, '#b9b9be', 9, -40, 120);\n\n  // título\n  const t1 = val('et1').toUpperCase(), t2 = val('et2').toUpperCase();\n  ctx.textAlign = 'left';\n  ctx.font = 'italic 900 92px Montserrat, sans-serif';\n  ctx.fillStyle = '#161619';\n  if(t1) ctx.fillText(t1, 80, 200);\n  ctx.fillStyle = RED;\n  if(t2) ctx.fillText(t2, 80, 308);\n\n  // carros preenchidos\n  const cars = [];\n  for(let i = 0; i < 4; i++){\n    const nome = val('e_nome'+i);\n    if(nome || state.estFotos[i])\n      cars.push({nome, ano: val('e_ano'+i), km: val('e_km'+i),\n                 preco: val('e_preco'+i), tag: val('e_tag'+i), foto: state.estFotos[i]});\n  }\n  if(!cars.length){\n    ctx.fillStyle = 'rgba(0,0,0,.35)';\n    ctx.font = '600 30px Montserrat, sans-serif';\n    ctx.textAlign = 'center';\n    ctx.fillText('PREENCHA OS CARROS DA LISTA', W/2, 900);\n    ctx.textAlign = 'left';\n  }\n\n  const areaTop = 400, areaBot = 1770;\n  const rowH = Math.min(372, (areaBot - areaTop) / Math.max(cars.length, 1));\n  const blockTop = areaTop + Math.max(0, (areaBot - areaTop - rowH*cars.length)/2);\n  const cardX = 60, cardW = 960;\n\n  cars.forEach((car, i) => {\n    const cardY = blockTop + i*rowH + 16;\n    const cardH = rowH - 32;\n    // a janela adota a proporção exata da foto: nada de faixas cinza nem carro cortado\n    const imgAspect = car.foto ? car.foto.width/car.foto.height : 1.5;\n    const photoW = Math.round(cardH * Math.max(1.0, Math.min(1.9, imgAspect)));\n\n    // card branco de linha inteira\n    ctx.save();\n    ctx.shadowColor = 'rgba(0,0,0,.10)'; ctx.shadowBlur = 26; ctx.shadowOffsetY = 8;\n    ctx.fillStyle = '#ffffff';\n    rr(cardX, cardY, cardW, cardH, 22); ctx.fill();\n    ctx.restore();\n\n    // foto à esquerda (inteira — sem recorte de fundo)\n    ctx.save();\n    rr(cardX, cardY, cardW, cardH, 22); ctx.clip();\n    ctx.beginPath(); ctx.rect(cardX, cardY, photoW, cardH); ctx.clip();\n    if(car.foto) drawPhoto(car.foto, cardX, cardY, photoW, cardH);\n    else placeholder(cardX, cardY, photoW, cardH, 'FOTO', false);\n    ctx.restore();\n\n    // chip discreto sobre a foto\n    if(car.tag){\n      const cFont = '700 21px Montserrat, sans-serif';\n      ctx.font = cFont;\n      const tw = ctx.measureText(car.tag.toUpperCase()).width;\n      ctx.fillStyle = RED;\n      rr(cardX + 16, cardY + 16, tw + 36, 38, 9); ctx.fill();\n      ctx.fillStyle = '#ffffff';\n      ctx.fillText(car.tag.toUpperCase(), cardX + 34, cardY + 43);\n    }\n\n    // textos à direita — a fonte do nome diminui sozinha p/ nunca cortar\n    const textX = cardX + photoW + 42;\n    const textW = cardX + cardW - textX - 36;\n    let nf = 41, nomeFont, nomeLines;\n    while(true){\n      nomeFont = `700 ${nf}px Montserrat, sans-serif`;\n      nomeLines = wrapLines(car.nome.toUpperCase(), nomeFont, textW);\n      if(nomeLines.length <= 2 || nf <= 29) break;\n      nf -= 2;\n    }\n    // evita linha órfã (uma palavrinha sozinha na 2ª linha)\n    if(nomeLines.length === 2 && nomeLines[1].length <= 4){\n      for(let t = nf - 2; t >= 30; t -= 2){\n        const tf = `700 ${t}px Montserrat, sans-serif`;\n        const tl = wrapLines(car.nome.toUpperCase(), tf, textW);\n        if(tl.length === 1){ nf = t; nomeFont = tf; nomeLines = tl; break; }\n      }\n    }\n    nomeLines = nomeLines.slice(0, 3);\n    const nameLH = nf + 9;\n    const anokm = [car.ano, car.km ? (car.km.toUpperCase().includes('KM') ? car.km.toUpperCase() : car.km + ' KM') : '']\n      .filter(Boolean).join('  ·  ');\n    const infoH = nomeLines.length*nameLH + (anokm ? 46 : 0) + (car.preco ? 58 : 0);\n    let ty = cardY + Math.max(24, (cardH - infoH)/2) + nf*.82;\n    ctx.font = nomeFont; ctx.fillStyle = '#17181b';\n    nomeLines.forEach(l => { ctx.fillText(l, textX, ty); ty += nameLH; });\n    if(anokm){\n      ty += 6;\n      ctx.font = '500 29px Montserrat, sans-serif'; ctx.fillStyle = '#7a7a81';\n      ctx.fillText(anokm, textX, ty);\n      ty += 58;\n    } else ty += 12;\n    if(car.preco){\n      ctx.font = '800 40px Montserrat, sans-serif'; ctx.fillStyle = RED;\n      ctx.fillText('R$ ' + car.preco, textX, ty);\n    }\n  });\n\n  // logo preta no rodapé\n  drawLogoBlack(W/2, 1848, 250);\n}\n\n/* ---------- RENDER (dispatch) ---------- */\n/* ================================================================\n   TIPO 4 — EDITORIAL (premium, integrado à foto — referência: layouts\n   de importadoras de luxo em que a foto full-bleed escurece na base e\n   vira a área de informação; funciona com QUALQUER foto, sem recorte\n   de fundo)\n================================================================ */\nconst ED = {\n  fonte: \"'Inter', 'Helvetica Neue', Helvetica, Arial, sans-serif\",\n  margem: 76,\n  fotoH: 1150,      // foto full-bleed no topo (~60%)\n  fusaoIni: 720,    // onde a fusão com o fundo começa\n};\n\n// Duas variações do mesmo layout: a foto se funde no escuro (noturno,\n// dramático) ou no claro (catálogo, fotos de estúdio/dia)\nconst ED_TEMAS = {\n  escuro: {\n    fundo1: '#0f1116', fundo2: '#151821',\n    fusaoRGB: '15,17,22',\n    titulo: '#ffffff', texto: '#c9ced6', medio: '#9aa1ab', suave: '#7d8590',\n    chipFundo: 'rgba(255,255,255,.10)', chipTexto: '#ffffff',\n    vermelho: '#9a1c1c', logoClara: true,\n  },\n  claro: {\n    fundo1: '#f2f2f4', fundo2: '#e9e9ec',\n    fusaoRGB: '242,242,244',\n    titulo: '#181818', texto: '#3d4148', medio: '#7d838d', suave: '#8b9096',\n    chipFundo: 'rgba(0,0,0,.07)', chipTexto: '#181818',\n    vermelho: '#9a1c1c', logoClara: true,\n  },\n};\n\nfunction edTextoEsq(text, x, y, font, spacing, color){\n  ctx.font = font; ctx.fillStyle = color; ctx.textBaseline = 'alphabetic';\n  let cx = x;\n  for(const ch of [...text]){\n    ctx.fillText(ch, cx, y);\n    cx += ctx.measureText(ch).width + spacing;\n  }\n  return cx - spacing - x;\n}\n\nfunction edChip(x, y, w, h, r){\n  ctx.beginPath();\n  ctx.moveTo(x + r, y);\n  ctx.arcTo(x + w, y, x + w, y + h, r);\n  ctx.arcTo(x + w, y + h, x, y + h, r);\n  ctx.arcTo(x, y + h, x, y, r);\n  ctx.arcTo(x, y, x + w, y, r);\n  ctx.closePath();\n}\n\nfunction renderEditorial(){\n  const M = ED.margem;\n  const T = ED_TEMAS[state.edTema] || ED_TEMAS.escuro;\n  // A área da foto segue a PROPORÇÃO NATURAL da imagem (quadrada = 1080px,\n  // 16:9 = ~608px): zoom 1 = foto inteira, sem corte e sem sobras.\n  const FH = state.foto1\n    ? Math.min(Math.round(W * state.foto1.height / state.foto1.width), 1150)\n    : ED.fotoH;\n\n  // fundo de base (a foto se funde nele)\n  const bg = ctx.createLinearGradient(0, 0, 0, H);\n  bg.addColorStop(0, T.fundo1);\n  bg.addColorStop(1, T.fundo2);\n  ctx.fillStyle = bg; ctx.fillRect(0, 0, W, H);\n\n  // foto full-bleed no topo — cover; horizontais/quadradas ajustam com os\n  // sliders da Foto 1 (fundo da foto NÃO é removido: ele é integrado)\n  if(state.foto1){\n    drawPhoto(state.foto1, 0, 0, W, FH, state.f1);\n  } else {\n    ctx.fillStyle = '#1a1e26'; ctx.fillRect(0, 0, W, FH);\n    ctx.fillStyle = 'rgba(255,255,255,.35)';\n    ctx.font = '400 24px ' + ED.fonte;\n    ctx.textAlign = 'center';\n    ctx.fillText('ENVIE A FOTO PRINCIPAL (horizontal ou quadrada)', W/2, FH*.55);\n    ctx.textAlign = 'left';\n  }\n\n  // fusão: a base da foto se dissolve suavemente no fundo do painel\n  const g = ctx.createLinearGradient(0, ED.fusaoIni, 0, FH);\n  g.addColorStop(0, `rgba(${T.fusaoRGB},0)`);\n  g.addColorStop(.55, `rgba(${T.fusaoRGB},.55)`);\n  g.addColorStop(1, `rgba(${T.fusaoRGB},1)`);\n  ctx.fillStyle = g;\n  ctx.fillRect(0, ED.fusaoIni, W, FH - ED.fusaoIni);\n\n  // logo pequena e discreta no topo (sobre a foto)\n  drawLogoWhite(W/2, 92, 150);\n\n  // ---------- painel de informação (ancorado no rodapé) ----------\n  let y = H - 500;\n\n  // rótulo de curadoria com filete vermelho mínimo\n  ctx.fillStyle = T.vermelho;\n  ctx.fillRect(M, y - 20, 44, 3);\n  edTextoEsq('SELEÇÃO ATTRA', M + 62, y - 12, '500 21px ' + ED.fonte, 6, T.medio);\n\n  // marca — protagonista tipográfico (branco, bold)\n  y += 74;\n  const marca = val('marca').toUpperCase();\n  if(marca){\n    let bs = 66;\n    ctx.font = `600 ${bs}px ` + ED.fonte;\n    while(bs > 40 && ctx.measureText(marca).width > W - 2*M){\n      bs -= 2; ctx.font = `600 ${bs}px ` + ED.fonte;\n    }\n    ctx.fillStyle = T.titulo;\n    ctx.fillText(marca, M, y);\n  }\n\n  // modelo — linha clara, uma linha, encolhe se precisar\n  y += 56;\n  const modelo = val('modelo').toUpperCase();\n  if(modelo){\n    let ms = 34;\n    ctx.font = `400 ${ms}px ` + ED.fonte;\n    while(ms > 24 && ctx.measureText(modelo).width > W - 2*M){\n      ms -= 1; ctx.font = `400 ${ms}px ` + ED.fonte;\n    }\n    ctx.fillStyle = T.texto;\n    ctx.fillText(modelo, M, y);\n  }\n\n  // ano | km | complemento\n  y += 52;\n  const meta = [\n    val('ano'),\n    val('km') ? val('km') + ' KM' : '',\n    val('kmextra').toUpperCase(),\n  ].filter(Boolean).join('   |   ');\n  if(meta){\n    ctx.font = '400 27px ' + ED.fonte;\n    ctx.fillStyle = T.medio;\n    ctx.fillText(meta, M, y);\n  }\n\n  // preço em chip translúcido — importante, não dominante\n  y += 74;\n  const preco = val('preco').replace(/^R\\$\\s*/i, '');\n  if(preco){\n    const ptxt = 'R$ ' + preco;\n    let ps = 44;\n    ctx.font = `500 ${ps}px ` + ED.fonte;\n    while(ps > 30 && ctx.measureText(ptxt).width > 560){\n      ps -= 1; ctx.font = `500 ${ps}px ` + ED.fonte;\n    }\n    const tw = ctx.measureText(ptxt).width;\n    const ch = ps + 44;\n    edChip(M, y, tw + 72, ch, 16);\n    ctx.fillStyle = T.chipFundo;\n    ctx.fill();\n    ctx.fillStyle = T.chipTexto;\n    ctx.fillText(ptxt, M + 36, y + ch/2 + ps*.36);\n    y += ch;\n  }\n\n}\n\nfunction render(){\n  ctx.clearRect(0, 0, W, H);\n  ctx.imageSmoothingEnabled = true;\n  ctx.imageSmoothingQuality = 'high';\n  ctx.textAlign = 'left';\n  if(state.tipo === 'destaque') renderDestaque();\n  else if(state.tipo === 'estoque') renderEstoque();\n  else if(state.tipo === 'editorial') renderEditorial();\n  else renderClassico();\n}\n\n/* ---------- monta os 4 carros do estoque ---------- */\nconst estDefaults = [\n  {nome:'Porsche 911 Carrera', ano:'2025/2026', km:'1.290', preco:'1.250.000', tag:'BLINDADO'},\n  {nome:'Mercedes AMG S 63 E Performance', ano:'2025/2025', km:'3.392', preco:'1.890.000', tag:'BLINDADO'},\n  {nome:'Audi RS Q8 TFSI', ano:'2020/2021', km:'12.584', preco:'790.000', tag:''},\n  {nome:'', ano:'', km:'', preco:'', tag:''},\n];\nconst estWrap = $('estoqueCars');\nestDefaults.forEach((d, i) => {\n  const div = document.createElement('div');\n  div.className = 'carblock';\n  div.innerHTML = `\n    <h4>CARRO ${i+1}</h4>\n    <label>Nome</label><input type=\"text\" id=\"e_nome${i}\" value=\"${d.nome}\">\n    <div class=\"row\">\n      <div><label>Ano</label><input type=\"text\" id=\"e_ano${i}\" value=\"${d.ano}\"></div>\n      <div><label>KM</label><input type=\"text\" id=\"e_km${i}\" value=\"${d.km}\"></div>\n    </div>\n    <div class=\"row\">\n      <div><label>Preço</label><input type=\"text\" id=\"e_preco${i}\" value=\"${d.preco}\"></div>\n      <div><label>Selo (opcional)</label><input type=\"text\" id=\"e_tag${i}\" value=\"${d.tag}\"></div>\n    </div>\n    <label>Foto</label><input type=\"file\" id=\"e_foto${i}\" accept=\"image/*\">`;\n  estWrap.appendChild(div);\n});\n\n/* ---------- eventos ---------- */\nfunction loadImg(file, cb){\n  const r = new FileReader();\n  r.onload = e => { const img = new Image(); img.onload = () => cb(img, e.target.result); img.src = e.target.result; };\n  r.readAsDataURL(file);\n}\n$('foto1').addEventListener('change', e => { if(e.target.files[0]) loadImg(e.target.files[0], img => { state.foto1 = img; autoFrameFoto1(img); render(); }); });\n$('foto2').addEventListener('change', e => { if(e.target.files[0]) loadImg(e.target.files[0], img => { state.foto2 = img; render(); }); });\n$('foto3').addEventListener('change', e => { if(e.target.files[0]) loadImg(e.target.files[0], img => { state.foto3 = img; render(); }); });\n$('foto4').addEventListener('change', e => { if(e.target.files[0]) loadImg(e.target.files[0], img => { state.foto4 = img; render(); }); });\nfor(let i = 0; i < 4; i++){\n  $('e_foto'+i).addEventListener('change', (e => {\n    const idx = i;\n    return ev => { if(ev.target.files[0]) loadImg(ev.target.files[0], img => { state.estFotos[idx] = img; render(); }); };\n  })());\n  ['e_nome','e_ano','e_km','e_preco','e_tag'].forEach(p =>\n    $(p+i).addEventListener('input', render));\n}\n$('logofile').addEventListener('change', e => {\n  if(e.target.files[0]) loadImg(e.target.files[0], (img, data) => {\n    state.logo = img;\n    try{ localStorage.setItem('attra_logo', data); }catch(_){}\n    render();\n  });\n});\n$('clearlogo').addEventListener('click', () => {\n  state.logo = null; localStorage.removeItem('attra_logo'); $('logofile').value = ''; render();\n});\n\n['marca','modelo','ano','preco','km','kmextra','b1','b2','b3',\n 'selo','et1','et2','corte'].forEach(id =>\n  $(id).addEventListener('input', render));\n\n[['f1zoom','f1','zoom'],['f1x','f1','x'],['f1y','f1','y'],\n ['f2zoom','f2','zoom'],['f2x','f2','x'],['f2y','f2','y']]\n.forEach(([id, obj, key]) => {\n  $(id).addEventListener('input', e => {\n    state[obj][key] = e.target.value/100;\n    render();\n  });\n});\n\n/* ---------- troca de tipo ---------- */\nfunction updateVisibility(){\n  const t = state.tipo;\n  $('sec-edtema').style.display    = t === 'editorial' ? '' : 'none';\n  $('corte-wrap').style.display    = t === 'classico' ? '' : 'none';\n  $('sec-busca').style.display     = t === 'estoque' ? 'none' : '';\n  $('sec-veiculo').style.display   = t === 'estoque' ? 'none' : '';\n  $('sec-destaques').style.display = t === 'classico' ? '' : 'none';\n  $('sec-specs').style.display     = t === 'destaque' ? '' : 'none';\n  $('sec-fotos').style.display     = t === 'estoque' ? 'none' : '';\n  $('sec-estoque').style.display   = t === 'estoque' ? '' : 'none';\n  $('kmextra-wrap').style.display  = t === 'classico' ? '' : 'none';\n  $('fotos-extra').style.display   = t === 'destaque' ? '' : 'none';\n  $('foto2-label').textContent     = t === 'destaque'\n    ? 'Foto de baixo 1 (interior / detalhe)' : 'Foto secundária (traseira / lateral — rodapé)';\n}\ndocument.querySelectorAll('.typebtn').forEach(btn => {\n  btn.addEventListener('click', () => {\n    document.querySelectorAll('.typebtn').forEach(b => b.classList.remove('active'));\n    btn.classList.add('active');\n    state.tipo = btn.dataset.tipo;\n    updateVisibility();\n    if(state.foto1) autoFrameFoto1(state.foto1);\n    render();\n  });\n});\n\n/* ---------- download ---------- */\n$('download').addEventListener('click', () => {\n  const clean = s => s.replace(/\\s+/g, '-').replace(/[^\\w\\-\\.]/g, '').replace(/-+/g,'-');\n  let name;\n  if(state.tipo === 'estoque') name = 'Attra-Estoque';\n  else {\n    name = [val('marca'), val('modelo'), val('ano')].filter(Boolean).map(clean).join('-') || 'criativo-attra';\n    if(state.tipo === 'destaque') name += '-DESTAQUE';\n  }\n  const a = document.createElement('a');\n  a.download = name + '-STORIES-v1.png';\n  a.href = cv.toDataURL('image/png');\n  a.click();\n});\n\n/* ---------- init ---------- */\n/* ---------- busca no estoque (preenche os campos; manual continua valendo) ---------- */\nconst fmtBR = n => Number(n).toLocaleString('pt-BR');\n\nasync function buscarEstoque(){\n  const q = val('estoquebusca');\n  const box = $('estoqueresultados');\n  $('estoquefotos').innerHTML = '';\n  if(!q){ box.innerHTML = ''; return; }\n  box.innerHTML = '<div class=\"hint\">Buscando no estoque…</div>';\n  try{\n    const r = await fetch('/api/vehicles?search=' + encodeURIComponent(q) + '&limit=8');\n    const d = await r.json();\n    const vs = (d.vehicles || []).slice(0, 8);\n    if(!vs.length){ box.innerHTML = '<div class=\"hint\">Nenhum veículo encontrado para \"' + q + '\".</div>'; return; }\n    box.innerHTML = '';\n    for(const v of vs){\n      const b = document.createElement('button');\n      b.type = 'button'; b.className = 'estq-item';\n      b.textContent = [v.brand, v.model, v.version, v.year_model].filter(Boolean).join(' ')\n        + ' — R$ ' + fmtBR(v.price) + ' · ' + fmtBR(v.mileage) + ' km';\n      b.addEventListener('click', () => aplicarVeiculo(v));\n      box.appendChild(b);\n    }\n  }catch(_){\n    box.innerHTML = '<div class=\"hint\">Busca indisponível aqui — funciona dentro do admin do site (menu Criativos).</div>';\n  }\n}\n\nfunction aplicarVeiculo(v){\n  $('marca').value  = (v.brand || '').toUpperCase();\n  $('modelo').value = [v.model, v.version].filter(Boolean).join(' ').toUpperCase();\n  $('ano').value    = v.year_model || '';\n  $('preco').value  = v.price ? fmtBR(v.price) : '';\n  $('km').value     = v.mileage ? fmtBR(v.mileage) : '';\n  if(!val('b1') && v.color) $('b1').value = 'Cor ' + v.color;\n  montarFotosEstoque(v);\n  render();\n}\n\nfunction montarFotosEstoque(v){\n  const wrap = $('estoquefotos');\n  wrap.innerHTML = '';\n  // /_next/image = proxy da própria origem → canvas continua exportável\n  for(const u of (v.photos || []).slice(0, 12)){\n    const t = document.createElement('img');\n    t.src = '/_next/image?url=' + encodeURIComponent(u) + '&w=256&q=60';\n    t.className = 'estq-thumb';\n    t.title = 'Clique: Foto principal · Shift+clique: Foto 2';\n    t.addEventListener('click', ev => {\n      const img = new Image();\n      img.onload = () => {\n        if(ev.shiftKey){ state.foto2 = img; }\n        else { state.foto1 = img; autoFrameFoto1(img); }\n        render();\n      };\n      img.src = '/_next/image?url=' + encodeURIComponent(u) + '&w=1080&q=85';\n    });\n    wrap.appendChild(t);\n  }\n}\n\ndocument.querySelectorAll('.edtemabtn').forEach(btn => {\n  btn.addEventListener('click', () => {\n    document.querySelectorAll('.edtemabtn').forEach(b => b.classList.remove('active'));\n    btn.classList.add('active');\n    state.edTema = btn.dataset.edtema;\n    render();\n  });\n});\n\n$('estoquebtn').addEventListener('click', buscarEstoque);\n$('estoquebusca').addEventListener('keydown', e => {\n  if(e.key === 'Enter'){ e.preventDefault(); buscarEstoque(); }\n});\n\nconst savedLogo = (()=>{ try{ return localStorage.getItem('attra_logo'); }catch(_){ return null; } })();\nif(savedLogo){ const img = new Image(); img.onload = () => { state.logo = img; render(); }; img.src = savedLogo; }\n\nupdateVisibility();\nrender();\nif(document.fonts && document.fonts.ready) document.fonts.ready.then(render);\nsetTimeout(render, 800);\n</script>\n</body>\n</html>\n"
